import{c as n,Z as i,Q as p,j as l,g as t,n as e,o,m as d}from"./chunks/framework.qjzPVSkb.js";const k=JSON.parse('{"title":"清晰指令五原则","description":"写出好 Prompt 的五条核心原则，每条原则配对比示例","frontmatter":{"title":"清晰指令五原则","description":"写出好 Prompt 的五条核心原则，每条原则配对比示例","difficulty":"beginner"},"headers":[],"relativePath":"prompts/principles.md","filePath":"prompts/principles.md"}'),r={name:"prompts/principles.md"},h={id:"清晰指令五原则",tabindex:"-1"};function c(u,a,b,g,m,v){const s=i("DifficultyBadge");return p(),l("div",null,[t("h1",h,[a[0]||(a[0]=e("清晰指令五原则 ",-1)),o(s,{level:"beginner"}),a[1]||(a[1]=e()),a[2]||(a[2]=t("a",{class:"header-anchor",href:"#清晰指令五原则","aria-label":'Permalink to "清晰指令五原则 <DifficultyBadge level="beginner" />"'},"​",-1))]),a[3]||(a[3]=d(`<p>写好 Prompt 并不需要什么神秘技巧。遵循以下五条原则，你的提示词质量就能大幅提升。</p><hr><h2 id="原则一-明确任务目标" tabindex="-1">原则一：明确任务目标 <a class="header-anchor" href="#原则一-明确任务目标" aria-label="Permalink to &quot;原则一：明确任务目标&quot;">​</a></h2><p>说清楚你要 AI 做什么，而不是让它猜。</p><h3 id="❌-不好" tabindex="-1">❌ 不好 <a class="header-anchor" href="#❌-不好" aria-label="Permalink to &quot;❌ 不好&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我写点东西。</span></span></code></pre></div><h3 id="✅-好" tabindex="-1">✅ 好 <a class="header-anchor" href="#✅-好" aria-label="Permalink to &quot;✅ 好&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我写一封离职邮件，语气礼貌得体，感谢公司的培养，不涉及任何负面内容。</span></span></code></pre></div><p><strong>技巧</strong>：用动词开头——&quot;写一封&quot;、&quot;总结以下&quot;、&quot;将以下翻译成&quot;、&quot;分析这段数据&quot;。</p><hr><h2 id="原则二-提供足够上下文" tabindex="-1">原则二：提供足够上下文 <a class="header-anchor" href="#原则二-提供足够上下文" aria-label="Permalink to &quot;原则二：提供足够上下文&quot;">​</a></h2><p>告诉 AI 背景信息：谁在用、为什么用、什么场景下用。</p><h3 id="❌-不好-1" tabindex="-1">❌ 不好 <a class="header-anchor" href="#❌-不好-1" aria-label="Permalink to &quot;❌ 不好&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解释一下 Vue 的响应式原理。</span></span></code></pre></div><h3 id="✅-好-1" tabindex="-1">✅ 好 <a class="header-anchor" href="#✅-好-1" aria-label="Permalink to &quot;✅ 好&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我的读者是刚学前端 3 个月的新手，请用通俗易懂的方式解释 Vue 的响应式原理，</span></span>
<span class="line"><span>用生活中的类比来帮助理解，避免使用专业术语。</span></span></code></pre></div><p><strong>技巧</strong>：至少回答三个问题——谁在看？需要什么程度的答案？什么场景下使用？</p><hr><h2 id="原则三-指定输出格式" tabindex="-1">原则三：指定输出格式 <a class="header-anchor" href="#原则三-指定输出格式" aria-label="Permalink to &quot;原则三：指定输出格式&quot;">​</a></h2><p>告诉 AI 你想要的输出结构和样式。</p><h3 id="❌-不好-2" tabindex="-1">❌ 不好 <a class="header-anchor" href="#❌-不好-2" aria-label="Permalink to &quot;❌ 不好&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>给我讲讲 Python 和 JavaScript 的区别。</span></span></code></pre></div><h3 id="✅-好-2" tabindex="-1">✅ 好 <a class="header-anchor" href="#✅-好-2" aria-label="Permalink to &quot;✅ 好&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请用表格对比 Python 和 JavaScript 的主要区别，包含以下维度：</span></span>
<span class="line"><span>类型系统、运行环境、主流用途、语法特点、社区生态。</span></span>
<span class="line"><span>表格后附一段 50 字以内的总结。</span></span></code></pre></div><p><strong>常用格式</strong>：表格、列表、JSON、Markdown、分步骤说明、摘要+详情。</p><hr><h2 id="原则四-给出示例-few-shot" tabindex="-1">原则四：给出示例（Few-Shot） <a class="header-anchor" href="#原则四-给出示例-few-shot" aria-label="Permalink to &quot;原则四：给出示例（Few-Shot）&quot;">​</a></h2><p>先给 AI 看 1-3 个你想得到的输出样例，它就能模仿你的风格。</p><h3 id="❌-不好-3" tabindex="-1">❌ 不好 <a class="header-anchor" href="#❌-不好-3" aria-label="Permalink to &quot;❌ 不好&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把这段文字改写成简洁版本。</span></span></code></pre></div><h3 id="✅-好-3" tabindex="-1">✅ 好 <a class="header-anchor" href="#✅-好-3" aria-label="Permalink to &quot;✅ 好&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请把以下句子改写成简洁版本，参考示例格式：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>示例：</span></span>
<span class="line"><span>原文：由于天气原因，原定于明天举行的户外活动将会被推迟到下周进行。</span></span>
<span class="line"><span>改写：明天活动因天气推迟至下周。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>现在请改写：由于系统正在进行维护升级，在此期间用户可能无法正常登录账户。</span></span></code></pre></div><p>更多示例技巧见 <a href="./few-shot.html">Few-Shot / Zero-Shot</a>。</p><hr><h2 id="原则五-约束边界" tabindex="-1">原则五：约束边界 <a class="header-anchor" href="#原则五-约束边界" aria-label="Permalink to &quot;原则五：约束边界&quot;">​</a></h2><p>明确告诉 AI <strong>不要做什么</strong>，和告诉它做什么同样重要。</p><h3 id="❌-不好-4" tabindex="-1">❌ 不好 <a class="header-anchor" href="#❌-不好-4" aria-label="Permalink to &quot;❌ 不好&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>推荐一些 Python 学习资源。</span></span></code></pre></div><h3 id="✅-好-4" tabindex="-1">✅ 好 <a class="header-anchor" href="#✅-好-4" aria-label="Permalink to &quot;✅ 好&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>推荐 5 个适合初学者的免费 Python 学习资源。</span></span>
<span class="line"><span>要求：</span></span>
<span class="line"><span>- 不包括视频教程（只要文章/文档/交互式平台）</span></span>
<span class="line"><span>- 每个资源附 1 句话推荐理由</span></span>
<span class="line"><span>- 不要推荐付费课程</span></span>
<span class="line"><span>- 优先中文资源</span></span></code></pre></div><hr><h2 id="五原则速查卡" tabindex="-1">五原则速查卡 <a class="header-anchor" href="#五原则速查卡" aria-label="Permalink to &quot;五原则速查卡&quot;">​</a></h2><table tabindex="0"><thead><tr><th>原则</th><th>一句话</th><th>关键词</th></tr></thead><tbody><tr><td>明确任务</td><td>说清楚做什么</td><td>动词开头</td></tr><tr><td>提供上下文</td><td>说清楚为谁做</td><td>读者、场景、深度</td></tr><tr><td>指定格式</td><td>说清楚怎么呈现</td><td>表格、列表、Markdown</td></tr><tr><td>给出示例</td><td>让 AI 看到样例</td><td>输入→输出示例</td></tr><tr><td>约束边界</td><td>说清楚不要什么</td><td>限制条件、排除项</td></tr></tbody></table><hr><h2 id="进阶阅读" tabindex="-1">进阶阅读 <a class="header-anchor" href="#进阶阅读" aria-label="Permalink to &quot;进阶阅读&quot;">​</a></h2><ul><li><a href="./structured-prompt.html">结构化提示词</a> — 把五原则融入结构化模板</li><li><a href="./system-prompt.html">System Prompt 设计</a> — 把规则固化到系统指令中</li></ul>`,46))])}const q=n(r,[["render",c]]);export{k as __pageData,q as default};
